head.script:
scwin.MSG_LO_WRN_008 = "이미 전표가 발행  되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_009 = "Department 가 변경 되었습니다.";
scwin.MSG_LO_WRN_010 = "변경된 내역을 저장 후 EDI Send를 할 수 있습니다.";
scwin.MSG_LO_WRN_011 = "Shipping Request를 전송하시겠습니까?";

scwin.statusFlag = "";
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.mhnoFlag = "0";

scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";
scwin.v_carrierBkno = "";
scwin.v_srno = "";

scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "O";
scwin.hd_mwarecd = "";
scwin.hd_mwarenm = "";
scwin.hd_mwareEngCd = "";

scwin.txt_hhlinernm = "";

scwin.userId = "";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.userId = $c.ses.getUserId();

    if (scwin.params != null) {
        scwin.v_linkcheck = scwin.params["linkcheck"] || "0";
        scwin.v_kcomcd = scwin.params["kcomcd"] || "";
        scwin.v_blno = scwin.params["blno"] || "";
        scwin.v_mhno = scwin.params["mhno"] || "";
        scwin.v_bkno = scwin.params["bkno"] || "";
        scwin.v_carrierBkno = scwin.params["carrierBkno"] || "";
        scwin.v_srno = scwin.params["srno"] || "";
    }

    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_ContainerTypeLoading();
    scwin.f_getParametrSetting(scwin.v_linkcheck);
};

scwin.f_getParametrSetting = function(gubun) {
    switch (gubun) {
        case "0":
            break;
        case "1":
            scwin.mhnoFlag = "1";
            if (scwin.v_blno == "null" || scwin.v_blno == "") {
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.setFocus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow();
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
            scwin.f_HblLoading();
            break;
        case "3":
            scwin.mhnoFlag = "1";
            cnd_ed_srno.setValue(scwin.v_srno);
            scwin.f_Retrieve();
            break;
        case "4":
            scwin.f_Create();
            cnd_ed_hhblno.setFocus();
            ica_hhetd.setFocus();
            break;
    }
};

scwin.f_Check = function() {
    if (scwin.statusFlag == "I") {
        acb_autono.setSelectedIndex(1);
        acb_hhpcgb.setSelectedIndex(0);
        acb_hhbltype.setSelectedIndex(0);
        acb_hhprenm.setSelectedIndex(0);
        acb_hhisunm.setSelectedIndex(1);
        acb_hhstype.setSelectedIndex(0);
        acb_hhcoload.setSelectedIndex(0);

        ed_input37.setValue("22GP");
        ed_input38.setValue("42GP");
        ed_input39.setValue("45GP");
        ed_input55.setValue("3");

        cbx_checkbox8.setValue("");
        cbx_checkbox9.setValue("");
        cbx_checkbox1.setValue("true");
        cbx_checkbox2.setValue("");
        cbx_checkbox3.setValue("");
        cbx_checkbox4.setValue("true");
        cbx_checkbox5.setValue("");
        cbx_checkbox6.setValue("true");

        rd_hhdanggb.setValue("N");
        rd_hhmnfgb.setValue("E");
    } else if (scwin.statusFlag == "C") {
        acb_autono.setSelectedIndex(1);
        acb_hhpcgb.setSelectedIndex(0);
        acb_hhbltype.setSelectedIndex(0);
        acb_hhprenm.setSelectedIndex(0);
        acb_hhisunm.setSelectedIndex(1);
        acb_hhstype.setSelectedIndex(0);
        acb_hhcoload.setSelectedIndex(0);

        ed_input37.setValue("22GP");
        ed_input38.setValue("42GP");
        ed_input39.setValue("45GP");
        ed_input55.setValue("3");

        cbx_checkbox8.setValue("");
        cbx_checkbox9.setValue("");
        cbx_checkbox1.setValue("true");
        cbx_checkbox2.setValue("");
        cbx_checkbox3.setValue("");
        cbx_checkbox4.setValue("true");
        cbx_checkbox5.setValue("");
        cbx_checkbox6.setValue("true");

        rd_hhdanggb.setValue("N");
        rd_hhmnfgb.setValue("E");
    }
};

scwin.f_DefaultValue = function() {
    scwin.f_Set("INIT");
    cnd_ed_hhblno.setFocus();
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save, btn_Delete, btn_Update,
                btn_CntrReceive, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfEnableBtnOnly([btn_Create]);
            scwin.f_DisablePopUpObj();
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel,
                btn_CntrReceive, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Delete]);
            gr_ocContList.setReadOnly("grid", true);
            gr_ocElList.setReadOnly("grid", true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            scwin.statusFlag = "";
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel,
                btn_CntrReceive, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            gr_ocContList.setReadOnly("grid", false);
            gr_ocElList.setReadOnly("grid", false);
            $c.gus.cfEnableObjects([cnd_ed_hhblno, acb_autono, cnd_ed_srno]);
            scwin.statusFlag = "C";
            break;
        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel,
                btn_CntrReceive, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            gr_ocContList.setReadOnly("grid", false);
            gr_ocElList.setReadOnly("grid", false);
            scwin.statusFlag = "U";
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([img_Date1, img_Date2, img_Date3, img_Date4, img_Date5]);
    $c.gus.cfEnableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7,
        img_PopUp13, img_PopUp17, img_PopUp18, img_PopUp19, img_PopUp20, img_PopUp21, img_PopUp22, img_PopUp23, img_PopUp24]);
};

scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([img_Date1, img_Date2, img_Date3, img_Date4, img_Date5]);
    $c.gus.cfDisableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7,
        img_PopUp13, img_PopUp17, img_PopUp18, img_PopUp19, img_PopUp20, img_PopUp21, img_PopUp22, img_PopUp23, img_PopUp24]);
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_hhblno.getValue().trim() == "" && cnd_ed_srno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No or S/R No"]);
        return;
    }

    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("mhno", acb_hhpcgb.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio);

    await $c.sbm.execute(sbm_retrieve);

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(acb_hhpcgb, true);
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([cnd_ed_hhblno, cnd_ed_srno]);
    acb_autono.setSelectedIndex(1);
    ds_hmhno.removeAll();
};

scwin.f_Create = function() {
    scwin.f_FieldClear();
    ds_hmhno.insertRow();

    ds_srList.removeAll();
    ds_srList.insertRow();
    ds_ocContList.removeAll();
    ds_ocElList.removeAll();

    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(acb_hhpcgb, true);
    $c.gus.cfEnableObj(cnd_ed_srno, true);

    scwin.f_Set("CREATE");
    scwin.f_Check();

    cnd_ed_srno.setValue("");
    cnd_ed_srno.setFocus();
};

scwin.f_Update = async function() {
    if (ica_hhetd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
        return;
    } else {
        scwin.f_Set("UPDATE");
    }
};

scwin.f_Save = async function() {
    if (ds_srList.isUpdated() || ds_ocContList.isUpdated() || ds_ocElList.isUpdated()) {
        let validResult = await scwin.f_validate();
        if (validResult) {
            let chk = await $c.gus.cfConfirmMsg(E_MSG_CM_CRM_001);
            if (chk) {
                if (scwin.statusFlag == "C") {
                    dma_retrieve.set("hhetd", ds_srList.getCellData(ds_srList.getRowPosition(), "hhetd"));
                    await $c.sbm.execute(sbm_retrieveSrno);
                    cnd_ed_srno.setValue(ds_retrieveNo.getCellData(0, "srno"));

                    let row = ds_srList.getRowPosition();
                    ds_srList.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                    ds_srList.setCellData(row, "hhblno", ed_input3.getValue());
                    ds_srList.setCellData(row, "srno", cnd_ed_srno.getValue());
                    ds_srList.setCellData(row, "mhno", acb_hhpcgb.getValue());
                    ds_srList.setCellData(row, "hhisunm", acb_hhisunm.getValue());
                    ds_srList.setCellData(row, "hhpaynm", acb_hhpaynm.getValue());
                    ds_srList.setCellData(row, "hhio", scwin.hd_hhio);
                    ds_srList.setCellData(row, "inpid", scwin.userId);

                    for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
                        ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                        ds_ocContList.setCellData(i, "mchblno", ed_input3.getValue());
                        ds_ocContList.setCellData(i, "inpid", scwin.userId);
                        ds_ocContList.setCellData(i, "srno", cnd_ed_srno.getValue());
                        ds_ocContList.setRowStatus(i, "C");
                    }

                    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
                        ds_ocElList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                        ds_ocElList.setCellData(i, "hhblno", ed_input3.getValue());
                        ds_ocElList.setCellData(i, "inpid", scwin.userId);
                        ds_ocElList.setCellData(i, "srno", cnd_ed_srno.getValue());
                        ds_ocElList.setRowStatus(i, "C");
                    }

                    ds_srList.setRowStatus(ds_srList.getRowPosition(), "C");
                }

                let hhs1Val = ds_srList.getCellData(ds_srList.getRowPosition(), "hhs1");
                if (hhs1Val != null && hhs1Val.length > 100) {
                    await $c.win.alert("Shipper명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + hhs1Val.length);
                    return false;
                }

                let hhc1Val = ds_srList.getCellData(ds_srList.getRowPosition(), "hhc1");
                if (hhc1Val != null && hhc1Val.length > 100) {
                    await $c.win.alert("Consignee명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + hhc1Val.length);
                    return false;
                }

                let hhn1Val = ds_srList.getCellData(ds_srList.getRowPosition(), "hhn1");
                if (hhn1Val != null && hhn1Val.length > 100) {
                    await $c.win.alert("Notify명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " + hhn1Val.length);
                    return false;
                }

                await $c.sbm.execute(sbm_save);

                $c.gus.cfEnableObj(cnd_ed_hhblno, true);
                $c.gus.cfEnableObj(acb_hhpcgb, true);

                cnd_ed_hhblno.setFocus();
                scwin.f_Set("SAVE");
            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["S/R"]);
    }
};

scwin.f_Send = async function() {
    if (ds_srList.isUpdated() || ds_ocContList.isUpdated() || ds_ocElList.isUpdated()) {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_010);
    } else {
        let chkTb1 = await $c.gus.cfValidate([gr_ocContList]);
        if (!chkTb1) return false;

        for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
            if (ds_ocContList.getCellData(i, "mcpkg") == "" || ds_ocContList.getCellData(i, "mcpkg") == "0") {
                await $c.win.alert("S/R의 컨테이너 정보에서 컨테이너 [" + ds_ocContList.getCellData(i, "mccntno") + "]의 PKG는 0보다 커야 합니다.");
                scwin.f_Update();
                return false;
            }
            if (ds_ocContList.getCellData(i, "mcwgt") == "" || ds_ocContList.getCellData(i, "mcwgt") == "0") {
                await $c.win.alert("S/R의 컨테이너 정보에서 컨테이너 [" + ds_ocContList.getCellData(i, "mccntno") + "]의 Weight은 0보다 커야 합니다.");
                scwin.f_Update();
                return false;
            }
            if (ds_ocContList.getCellData(i, "mcmsr") == "" || ds_ocContList.getCellData(i, "mcmsr") == "0") {
                await $c.win.alert("S/R의 컨테이너 정보에서 컨테이너 [" + ds_ocContList.getCellData(i, "mccntno") + "]의 Measure는 0보다 커야 합니다.");
                scwin.f_Update();
                return false;
            }
        }

        let chkSend = await $c.win.confirm(scwin.MSG_LO_WRN_011);
        if (chkSend) {
            if (cnd_ed_srno.getValue().trim() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["S/R No"]);
                return;
            }

            ds_srList.setRowStatus(ds_srList.getRowPosition(), "C");

            for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
                ds_ocContList.setRowStatus(i, "C");
            }
            for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
                ds_ocElList.setRowStatus(i, "C");
            }

            await $c.sbm.execute(sbm_send);
        }
    }
};

scwin.f_Cancel = function() {
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    $c.gus.cfEnableObj(acb_hhpcgb, true);

    cnd_ed_hhblno.setFocus();

    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        ds_srList.undoAll();
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
    }
};

scwin.f_Delete = async function() {
    let chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk) {
        ds_srList.removeAll();
        await $c.sbm.execute(sbm_delete);

        cnd_ed_hhblno.setValue("");
        ds_srList.removeAll();
        ds_ocContList.removeAll();
        ds_ocElList.removeAll();

        $c.gus.cfEnableObj(cnd_ed_hhblno, true);
        $c.gus.cfEnableObj(acb_hhpcgb, true);

        cnd_ed_hhblno.setFocus();
        scwin.f_Set("INIT");
    }
};

scwin.f_addRow = async function(disGubun) {
    switch (disGubun) {
        case 1:
            if (cnd_ed_hhblno.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            } else {
                if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["HEADER"]);
                    return;
                } else {
                    let newRow = ds_ocContList.insertRow();
                    ds_ocContList.setCellData(newRow, "kcomcd", scwin.hd_kcomcd);
                    ds_ocContList.setCellData(newRow, "mchblno", cnd_ed_hhblno.getValue());
                    ds_ocContList.setCellData(newRow, "srno", cnd_ed_srno.getValue());
                    ds_ocContList.setCellData(newRow, "inpid", scwin.userId);
                    ds_ocContList.setCellData(newRow, "mcpart", "N");
                    gr_ocContList.setFocusedCell(newRow, "mccntno");
                }
            }
            break;
        case 2:
            if (cnd_ed_hhblno.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            } else {
                if (cnd_ed_hhblno.getValue().length == 4 && cnd_ed_hhblno.getValue() == "DBEX") {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["HEADER"]);
                    return;
                } else {
                    let newRow = ds_ocElList.insertRow();
                    ds_ocElList.setCellData(newRow, "kcomcd", scwin.hd_kcomcd);
                    ds_ocElList.setCellData(newRow, "hhblno", cnd_ed_hhblno.getValue());
                    ds_ocElList.setCellData(newRow, "srno", cnd_ed_srno.getValue());
                    ds_ocElList.setCellData(newRow, "inpid", scwin.userId);
                    ds_ocElList.setCellData(newRow, "pgb", "N");
                    gr_ocElList.setFocusedCell(newRow, "elno");
                }
            }
            break;
        default:
            break;
    }
};

scwin.f_deleteRow = function(disGubun) {
    switch (disGubun) {
        case 1:
            ds_ocContList.removeRow(ds_ocContList.getRowPosition());
            break;
        case 2:
            ds_ocElList.removeRow(ds_ocElList.getRowPosition());
            break;
        default:
            break;
    }
};

scwin.f_cancelRow = function(disGubun) {
    switch (disGubun) {
        case 1:
            ds_ocContList.undoAll();
            break;
        case 2:
            ds_ocElList.undoAll();
            break;
        default:
            break;
    }
};

scwin.f_validate = async function() {
    let chkValid = await $c.gus.cfValidate([ed_input3, ed_carrierBkNo, ica_hhetd]);
    if (!chkValid) return false;

    if (ica_hhetd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]);
        ica_hhetd.setFocus();
        return false;
    }

    if (ica_hheta.getValue() != "") {
        if (!$c.gus.cfIsAfterDate(ica_hhetd.getValue(), ica_hheta.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
            ica_hhetd.setFocus();
            return false;
        }
    }

    if (acb_hhpaynm.getValue() == "DESTINATION") {
        if (ds_srList.getCellData(ds_srList.getRowPosition(), "hhfdcd") == "") {
            await $c.win.alert("지불장소의 Destination 이 지정되지 않았습니다.");
            return false;
        }
    }

    if (ds_srList.getCellData(ds_srList.getRowPosition(), "hhitem") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]);
        return false;
    }

    if (ds_srList.getCellData(ds_srList.getRowPosition(), "hhmitem1") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item Name"]);
        return false;
    }

    if (scwin.statusFlag == "C") {
        if (cnd_ed_hhblno.getValue().length != 4 && cnd_ed_hhblno.getValue().substring(0, 4) == "DBEX") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_026, ["Auto Create", "DBEX"]);
            cnd_ed_hhblno.setFocus();
            return false;
        }
    }

    let cntType1 = ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt1type");
    if (cntType1 != "") {
        let found = scwin.f_findContainerType(cntType1);
        if (!found) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            return false;
        }
    }
    let cntType2 = ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt2type");
    if (cntType2 != "") {
        let found = scwin.f_findContainerType(cntType2);
        if (!found) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            return false;
        }
    }
    let cntType3 = ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt3type");
    if (cntType3 != "") {
        let found = scwin.f_findContainerType(cntType3);
        if (!found) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            return false;
        }
    }
    let cntType4 = ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt4type");
    if (cntType4 != "") {
        let found = scwin.f_findContainerType(cntType4);
        if (!found) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            return false;
        }
    }

    for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
        if (ds_ocContList.getCellData(i, "mccntno") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container"]);
            gr_ocContList.setFocusedCell(i, "mccntno");
            return false;
        }
    }
    for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
        if (ds_ocContList.getCellData(i, "mctype") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Type"]);
            gr_ocContList.setFocusedCell(i, "mctype");
            return false;
        }
    }

    let v_elno = "";
    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "elno") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["수출신고번호"]);
            gr_ocElList.setFocusedCell(i, "elno");
            return false;
        } else {
            v_elno = ds_ocElList.getCellData(i, "elno");
            if (rd_hhmnfgb.getValue() == "E") {
                if (ds_ocElList.getCellData(i, "elno").length != 15) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["수출신고번호"]);
                    return false;
                }
                if (!scwin.f_elnoExportCheck(v_elno)) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["수출신고번호"]);
                    return false;
                }
            } else if (rd_hhmnfgb.getValue() == "I") {
                if (ds_ocElList.getCellData(i, "elno").length != 18) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["화물관리번호"]);
                    return false;
                }
                if (!scwin.f_elnoReshipmentCheck(v_elno)) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_038, ["화물관리번호"]);
                    return false;
                }
            }
        }
    }

    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "unit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_ocElList.setFocusedCell(i, "unit");
            return false;
        }
    }
    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "pkg") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Package"]);
            gr_ocElList.setFocusedCell(i, "pkg");
            return false;
        }
    }
    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "wgt") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Weight"]);
            gr_ocElList.setFocusedCell(i, "wgt");
            return false;
        }
    }
    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "mgb") != "") {
            if (ds_ocElList.getCellData(i, "mpkg") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["package"]);
                gr_ocElList.setFocusedCell(i, "mpkg");
                return false;
            }
            if (ds_ocElList.getCellData(i, "mut") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
                gr_ocElList.setFocusedCell(i, "mut");
                return false;
            }
        }
    }
    for (let i = 0; i < ds_ocElList.getRowCount(); i++) {
        if (ds_ocElList.getCellData(i, "pgb") == "Y") {
            if (ds_ocElList.getCellData(i, "pseq") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ISO"]);
                gr_ocElList.setFocusedCell(i, "pseq");
                return false;
            }
        }
    }

    if (acb_hhbltype.getValue() == "B"
        && (ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt1") != "0"
            || ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt2") != "0"
            || ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt3") != "0"
            || ds_srList.getCellData(ds_srList.getRowPosition(), "hhcnt4") != "0")) {
        let msg = "Cargo Type이 Bulk 이면서 Container정보가 입력되었습니다.\n입력된 정보가 맞으시면 확인처리 해 주십시오.";
        let chk = await $c.win.confirm(msg);
        if (!chk) {
            return false;
        }
    }

    return true;
};

scwin.f_findContainerType = function(typeCode) {
    for (let i = 0; i < ds_containerType.getRowCount(); i++) {
        if (ds_containerType.getCellData(i, "code") == typeCode) {
            return true;
        }
    }
    return false;
};

scwin.f_getContainerTypeName = function(typeCode) {
    for (let i = 0; i < ds_containerType.getRowCount(); i++) {
        if (ds_containerType.getCellData(i, "code") == typeCode) {
            return ds_containerType.getCellData(i, "name");
        }
    }
    return "";
};

