scwin.f_openPgm = function(name) {
    if (name == "MasterBL") {
        if (acb_hhpcgb.getValue() == "NONE" || acb_hhpcgb.getValue() == "") {
            let param = {
                linkcheck: "5",
                kcomcd: scwin.hd_kcomcd,
                vslcd: ds_srList.getCellData(ds_srList.getRowPosition(), "hhvslcd"),
                vsl: ds_srList.getCellData(ds_srList.getRowPosition(), "hhvsl"),
                vyg: ds_srList.getCellData(ds_srList.getRowPosition(), "hhvyg")
            };
            $c.win.openMenu("Export Master B/L", "/ui/il/seaout/sobl/se_106_01_01b.xml", "se_106_01_01b.xml", param);
        } else {
            let param = {
                linkcheck: "3",
                kcomcd: scwin.hd_kcomcd,
                blno: ed_input3.getValue(),
                mhno: acb_hhpcgb.getValue()
            };
            $c.win.openMenu("Export Master B/L", "/ui/il/seaout/sobl/se_106_01_01b.xml", "se_106_01_01b.xml", param);
        }
    }
};

