scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_srList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
        scwin.f_Set("INIT");
        scwin.f_Check();
    } else {
        let v_totPkg = 0;
        let v_totWgt = 0;
        let v_totMsr = 0;
        for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
            v_totPkg += parseFloat(ds_ocContList.getCellData(i, "mcpkg")) || 0;
            v_totWgt += parseFloat(ds_ocContList.getCellData(i, "mcwgt")) || 0;
            v_totMsr += parseFloat(ds_ocContList.getCellData(i, "mcmsr")) || 0;
        }
        ed_input60.setValue(v_totPkg);
        ed_input61.setValue(v_totWgt);
        ed_input62.setValue(v_totMsr);
        cnd_ed_hhblno.setValue(ds_srList.getCellData(ds_srList.getRowPosition(), "hhblno"));
        scwin.f_Set("RETRIEVE");
    }
};

